"""
MKT Original — Mark 12–13
Output: data/commentary/mkt-original/mark.json
Skips already-present: 12:29, 13:26
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_12_13 = {
"12": {
"1": "<p><strong>ampelourgos / phragmon / hypolēnion / pyrgon</strong> — vineyard / wall / pit / tower — the parable's opening vocabulary closely mirrors LXX Isaiah 5:1–2 (<em>ōdē tou agapētou</em>, the song of the beloved): Isaiah's vineyard allegory names Israel as the LORD's vineyard. Jesus activates that intertextual memory immediately. The Greek <em>parabolas</em> (parables, plural) may anticipate the series of controversies, though only this parable is narrated. <em>Geōrgois</em> (tenant-farmers, sharecroppers) sets up the social dynamic of absentee landowner and working tenants.</p>",
"2": "<p><strong>apostellō / doulos</strong> — sent / slave-servant — <em>apostellō</em> is the same verb from which <em>apostolos</em> (apostle) derives. Here it describes the repeated sending of prophetic servants. <em>Doulos</em> (slave, servant) was the standard LXX term for the prophets as servants of God (Amos 3:7: <em>paideias autou tous doulous autou tous prophētas</em>). The allegorical layer is immediately visible.</p>",
"3": "<p><strong>dero</strong> — beat/flog — <em>dero</em> literally means to flay or skin (related to <em>derma</em>, skin). It is a graphic verb for violent treatment, used for the prophet beaten and sent back empty-handed (<em>kenon</em>). The emptiness (<em>kenon</em>) reverses the expectation of fruit (<em>karpon</em>) in v.2.</p>",
"4": "<p><strong>ekephaliōsan kai ētimasan</strong> — they struck him on the head and dishonored him — <em>ekephaliōsan</em> (they struck on the head) is a rare verb, possibly coined from <em>kephalē</em> (head). The Greek textual tradition shows variants here; some manuscripts read <em>ekthalamōsan</em> (handled shamefully/wounded). The cumulative pattern of intensifying violence against successive servants mirrors the Deuteronomistic history's account of Israel's rejection of prophets.</p>",
"5": "<p><strong>tous men... tous de</strong> — some... others — the correlative construction (<em>tous men derontes, tous de apokteinontes</em>) creates a chiastic escalation: beating escalates to killing. The parable does not individualize each servant; the pattern is corporate — Israel's repeated rejection of the prophetic word.</p>",
"6": "<p><strong>agapēton huion / eschatōs</strong> — a beloved son / last of all — <em>agapēton</em> (beloved, dear one) directly echoes the voice at Jesus's baptism (1:11: <em>ho huios mou ho agapētos</em>) and transfiguration (9:7). The allegorical identification of the son with Jesus is transparent. <em>Eschatōs</em> (last of all) signals the finality of this sending — there is no further recourse after the son. <em>Hoti entrapēsontai ton huion mou</em> (they will respect my son) — the owner's reasoning proves tragically mistaken.</p>",
"7": "<p><strong>deute apokteinōmen auton / klēronomia</strong> — come let us kill him / the inheritance — the tenants' deliberation (<em>pros heautous</em>, among themselves) exposes the logic of self-serving violence: if the heir is removed, the inheritance passes to them. The Greek word <em>klēronomia</em> (inheritance, patrimony) carries covenantal weight — it is the term for Israel's land inheritance in the LXX.</p>",
"8": "<p><strong>exebalon exō tou ampelōnos</strong> — they threw him outside the vineyard — note the order in Mark: killed first, then threw out. Luke 20:15 reverses this (threw out, then killed), perhaps to echo Isa 5:5's vineyard-demolition imagery more explicitly. Mark's order — killed inside, then thrown out — may reflect the reality that Jesus was crucified <em>outside</em> the city walls (Heb 13:12), a detail the Markan audience would recognize.</p>",
"9": "<p><strong>apolesai / dōsei ton ampelōna allois</strong> — to destroy / will give the vineyard to others — <em>apolesai</em> (to destroy, to kill) echoes the tenants' own action against the son. The owner's judgment is retributive in kind. <em>Allois</em> (to others) is theologically loaded: the vineyard/covenant-community passes to a new people. This is the parable's climax.</p>",
"10": "<p><strong>lithos hon apedokimasan hoi oikodomountes, houtos egenēthē eis kephalēn gōnias</strong> — the stone that the builders rejected has become the cornerstone — Psalm 118:22 citation. This is the same Psalm whose <em>hōsanna</em> and <em>eulogēmenos ho erchomenos</em> (118:25–26) were shouted in the triumphal entry (11:9–10), creating a tight intertextual frame around the temple controversies. <em>Apedokimasan</em> (they rejected — from <em>dokimazō</em>, to test and reject as unworthy) is the builders' verdict, overturned by God. <em>Kephalē gōnias</em> (head of the corner) denotes the foundational stone that locks two walls together.</p>",
"11": "<p><strong>para kyriou egeneto hautē / thaumastē</strong> — this is from the Lord / wonderful/marvelous — Psalm 118:23. The divine reversal is not merely surprising but <em>thaumastē</em> (marvelous, awe-inspiring). The LXX quotation is verbatim, following the citation from 118:22. The implicit point: Jesus the rejected son is the stone God is making the cornerstone.</p>",
"12": "<p><strong>ekratēsai auton / ephobēthēsan ton ochlon / parabolēn eipen pros autous</strong> — to seize him / feared the crowd / spoken the parable against them — <em>ekratēsai</em> (to seize, arrest) — the desire is frustrated by crowd dynamics. The leaders' recognition that <em>pros autous</em> (against them) the parable was aimed shows their interpretive accuracy, which is ironic: they understand the parable better than they would like.</p>",
"13": "<p><strong>Pharisaioi kai Hērōdianoi / agreusosin</strong> — Pharisees and Herodians / to trap/snare him — the alliance of Pharisees and Herodians is unusual — they represent opposing political orientations — but they were allied earlier in a plot against Jesus (3:6). <em>Agreusosin</em> is a hunting term (<em>agreuo</em> = to catch prey), revealing the predatory intent beneath the flattering opening words.</p>",
"14": "<p><strong>ou melet soi peri oudenos / hodos tou theou / kēnsos</strong> — it does not concern you about anyone / the way of God / census-tax — <em>ou melet soi</em> (it is no concern to you = you do not regard persons) is ironic flattery preparing the trap. <em>Hodos tou theou</em> (the way of God, or: God's way) — the phrase has an existential ring. <em>Kēnsos</em> is the Latin <em>census</em> borrowed into Greek — the annual Roman head-tax (*tributum capitis*) that was politically explosive for Jews, since paying it acknowledged Rome's sovereignty over the land of Israel.</p>",
"15": "<p><strong>hypokrisin / dēnarion</strong> — hypocrisy / denarius — <em>hypokrisin</em> (hypocrisy, play-acting) — Jesus sees through the performance immediately. The <em>dēnarion</em> (denarius) was a silver Roman coin worth a day's wage for a laborer. It bore the image (<em>eikōn</em>) and inscription (<em>epigraphē</em>) of the emperor. Jesus's request to see one places his questioners in a slight awkward position: they are already carrying the coin of the occupying power.</p>",
"16": "<p><strong>eikōn kai epigraphē</strong> — image and inscription — The denarius of Tiberius bore on the obverse his portrait with the inscription <em>TI CAESAR DIVI AUG F AUGUSTUS</em> (Tiberius Caesar, son of the divine Augustus, Augustus) and on the reverse <em>PONTIF MAXIM</em> (Pontifex Maximus). The coin thus made religious claims. Jesus's question forces the crowds to articulate whose image they have been using.</p>",
"17": "<p><strong>apodote ta Kaisaros Kaisari kai ta tou theou tō theō</strong> — give back to Caesar what is Caesar's and to God what is God's — <em>apodote</em> is render/give back (not merely give), suggesting the coin already belongs to Caesar and is being returned. The deeper irony: the <em>eikōn tou theou</em> (image of God) from Genesis 1:26–27 belongs to the one who bears it — human beings — so to give to God what is God's means to give oneself. The crowds are <em>exethaumas</em>-ed (greatly amazed).</p>",
"18": "<p><strong>Saddoukaioi / hoi legousin anastasin mē einai</strong> — Sadducees / who say there is no resurrection — Mark's parenthetical identification of the Sadducees (who accepted only the written Torah and rejected resurrection as a Pharisaic innovation) is written for readers who may not know them. The resurrection controversy is the theological center of this section.</p>",
"19": "<p><strong>leviratus / epigambreuō</strong> — levirate law — the <em>levirate</em> (from Latin <em>levir</em>, husband's brother) obligation is cited from Deuteronomy 25:5–6. The Greek verb <em>epigambreuō</em> (to marry the widow as kinsman-redeemer) appears in the LXX Deut 25:5. The law preserved the deceased brother's name and inheritance. The Sadducees' scenario is constructed to make the resurrection appear absurd.</p>",
"20": "<p><strong>hepta adelphoi</strong> — seven brothers — the number seven is rhetorically chosen for its completeness: the scenario exhausts every possibility before arriving at the widow. The Sadducees intend the scenario to produce a logical reductio ad absurdum of resurrection belief.</p>",
"21": "<p><strong>apethanen mē katalipōn sperma</strong> — died leaving no seed — <em>sperma</em> (seed, offspring) is the covenant word for descendants. Each brother dies childless (<em>mē katalipōn sperma</em>), which perpetuates the levirate obligation to the next brother. The repetition is deliberate rhetorical accumulation.</p>",
"22": "<p><strong>eschaton / kai hē gynē apethanen</strong> — finally / the woman also died — the legal chain is complete: all seven marriages ended without children, and at last the woman herself died. The phrase <em>eschaton pantōn</em> (last of all) echoes 12:6's description of the beloved son sent last. The scenario has been constructed with cold logic to press the resurrection question.</p>",
"23": "<p><strong>en tē anastasei... tinos autōn estai gynē</strong> — in the resurrection... whose wife will she be — the Sadducees' question assumes that resurrection life reproduces earthly institutional structures (marriage, kinship, legal obligation). Jesus's answer in v.25 dismantles this assumption entirely by describing the resurrection state in categorically different terms.</p>",
"24": "<p><strong>planasthe / mē eidotes tas graphas mēde tēn dynamin tou theou</strong> — you are in error / not knowing the Scriptures nor the power of God — Jesus diagnoses the Sadducees' error as double: (1) ignorance of Scripture — specifically the Torah they claim as their sole authority; (2) ignorance of God's power to create new modes of existence. The verb <em>planasthe</em> (you are led astray, you err) uses the same root as the false teachers/prophets who will deceive in 13:5–6, 22.</p>",
"25": "<p><strong>hōs angeloi en tois ouranois eisin</strong> — they are like the angels in heaven — the resurrection state is not a continuation of earthly relational-legal structures but something categorically different. <em>Gamousin oute gamizontai</em> (they neither marry nor are given in marriage) — the two Greek verbs distinguish active (marrying) and passive (being given in marriage, typically for women). The angel-comparison evokes immortality and pure worship-existence, not dis-embodiment.</p>",
"26": "<p><strong>epi tou batou / egō ho theos Abraam / Isaak / Iakōb</strong> — in the passage of the bush / I am the God of Abraham / Isaac / Jacob — Exodus 3:6 citation. Jesus argues from within the Torah — the Sadducees' own scripture. The key is the verb tense: God says <em>egō eimi</em> (I AM) the God of Abraham, not <em>ēmēn</em> (I was). Since God says this to Moses centuries after Abraham's death, Abraham must still be alive — actively in relationship with God. Jesus reads a resurrection-warrant out of the burning bush passage.</p>",
"27": "<p><strong>theos zōntōn, ou nekrōn / polu planasthe</strong> — God of the living, not of the dead / you greatly err — the aphorism crystallizes the argument: a God of the <em>nekrōn</em> (dead) would be god of the non-existent. The divine name is the pledge of resurrection. <em>Polu planasthe</em> (you greatly/widely err) is emphatic — the adverb intensifies the verdict.</p>",
"28": "<p><strong>grammateus / poia estin prōtē pantōn entolē</strong> — a scribe / which is the first of all commandments — this scribe functions differently from the hostile interlocutors of 12:13–27. He comes because he has heard Jesus debate well (<em>kalōs apekrythē</em>, he answered well) and asks an authentic question. The rabbinic debate about which commandment was greatest (<em>prōtē / megalē</em>) was genuine: attempts to identify the foundational principle of Torah were common in Second Temple Judaism.</p>",
"30": "<p><strong>agapēseis kyrion ton theon sou / kardia / psychē / dianoia / ischys</strong> — love the Lord your God / heart / soul / mind / strength — the Shema citation (Deut 6:4–5) in this verse lists four faculties; Mark's version adds <em>dianoia</em> (mind/understanding) to the Hebrew's three (heart, soul, strength). The LXX of Deut 6:5 varies: some versions give three terms, some four. The addition of <em>dianoia</em> (rational/cognitive faculty) may reflect a Hellenistic-Jewish amplification. <em>Ex holēs</em> (with all of) is repeated four times — the comprehensive commitment leaves no faculty exempt.</p>",
"31": "<p><strong>agapēseis ton plēsion sou hōs seauton</strong> — love your neighbor as yourself — Leviticus 19:18. The conjunction of Deut 6:4–5 and Lev 19:18 as the two supreme commandments is attested in contemporaneous Jewish sources (Testament of the Twelve Patriarchs; Philo). <em>Meizon</em> (greater, comparative) — Jesus describes these as greater than all other commandments; the superlative would be <em>megistē</em>. The comparison to all other commandments is implicit.</p>",
"32": "<p><strong>heis estin kai ouk estin allos plēn autou</strong> — he is one and there is no other besides him — the scribe's response affirms radical monotheism. He supplements Jesus's citation with an echo of Deut 4:35: <em>ouk estin plēn autou</em>. Notably, the scribe extends the application to ethics, linking love-commands to the prophetic critique of sacrifice (Hosea 6:6; 1 Sam 15:22).</p>",
"33": "<p><strong>holokautōmata kai thysias</strong> — whole burnt offerings and sacrifices — <em>holokautōma</em> (whole burnt offering — the entire animal burned) and <em>thysia</em> (sacrifice — peace offering where some is eaten). The scribe invokes the prophetic subordination of cultic acts to moral love. This is striking given the setting: the conversation is occurring in the temple precincts. The scribe implicitly aligns with the prophetic critique of pure ritualism.</p>",
"34": "<p><strong>nounechōs / ou makran ei apo tēs basileias tou theou</strong> — wisely/sensibly / you are not far from the kingdom of God — <em>nounechōs</em> (sensibly, with good sense) is a hapax legomenon in the NT (only here). <em>Ou makran</em> (not far) is a spatial metaphor — proximity without arrival. The scribe is not yet *in* the kingdom. The statement is simultaneously commendation and implicit invitation. After this exchange, no one dared (<em>etolma</em>) to ask any more questions.</p>",
"35": "<p><strong>Christos huios Daueid</strong> — the Messiah is the son of David — Jesus initiates this question himself in the temple courts. The scribal tradition identified the Messiah as a Davidic king (2 Sam 7:12–16; Isa 11:1). Jesus does not deny the Davidic connection but probes how it can be reconciled with Psalm 110:1, where David calls the Messiah <em>kyrios</em>.</p>",
"36": "<p><strong>eipen kyrios tō kyriō mou / kathō ek dexiōn mou</strong> — the Lord said to my Lord / sit at my right hand — Psalm 110:1 (<em>LXX: eipen ho kyrios tō kyriō mou</em>). This was the most-cited OT text in early Christianity. Jesus attributes the psalm to David, who spoke it <em>en tō pneumati tō hagiō</em> (by the Holy Spirit) — Mark's only use of this phrase for Davidic inspiration. The problem: if David calls the Messiah <em>kyrios</em> (Lord/Master), then the Messiah is David's superior, not merely his descendant.</p>",
"37": "<p><strong>autos Dauid legei auton kyrion / pothen autou estin huios</strong> — David himself calls him Lord / how is he his son — the rhetorical question stands without resolution in Mark. Jesus does not deny Davidic sonship but relativizes it: Davidic descent does not exhaust the Messiah's identity. The christological implication is that the Messiah is simultaneously Son of David (by lineage) and Lord of David (by divine nature). <em>Ho polys ochlos ēkouen autou hēdeōs</em> (the great crowd heard him gladly/with pleasure).</p>",
"38": "<p><strong>blepe / thelontōn en stolais peripatein</strong> — watch out / wanting to walk in long robes — <em>blepe</em> (watch, beware) opens the warning. <em>Stolai</em> (flowing robes, stoles) were distinctive garments marking high social status. <em>Aspasmous en tais agorais</em> (greetings in the marketplaces) — public salutation ceremonies affirmed social hierarchy.</p>",
"39": "<p><strong>prōtokathedrias / prōtoklisias</strong> — first seats / first reclining-places — <em>prōtokathedria</em> (first/chief seat in the synagogue, facing the congregation) and <em>prōtoklisia</em> (first place at a banquet couch, highest honor position) — both compound honor-markers. The scribes are depicted as performing religiosity for social advancement.</p>",
"40": "<p><strong>katesthiousin / chrēas tōn chērōn / perissoteron krima</strong> — they devour / houses of widows / more severe judgment — <em>katesthiō</em> (to devour, consume) is a vivid verb for economic exploitation. Widows were among the most economically vulnerable in first-century Jewish society (no inheritance rights, dependent on male family members). <em>Prophasis</em> (under pretext/for show) makes lengthy prayers. The word recalls the critique of performative piety. <em>Perissoteron krima</em> (more severe judgment/condemnation) — the gravity of their sin is proportional to their public prominence and exploitation of the vulnerable.</p>",
"41": "<p><strong>gazophylakion / theōrei / ochlos ballen chalkon</strong> — treasury / was watching / the crowd was throwing copper coins — <em>gazophylakion</em> (treasury, literally: the place where <em>gaza</em> [Persian: treasure] is kept). Jesus <em>kathisas</em> (having sat down opposite) — a teaching posture of deliberate attention. The imperfect <em>eballen</em> (they were throwing/kept throwing) is vivid and iterative, painting the ongoing stream of worshippers.</p>",
"42": "<p><strong>ptōchē chēra / lepta dyo ho estin kodrantēs</strong> — a poor widow / two lepta which is a quadrans — <em>ptōchē</em> (destitute/beggar-poor, not merely <em>penēs</em>, working-poor) combined with <em>chēra</em> (widow) marks the lowest economic status. <em>Lepta</em> (singular: <em>lepton</em>) were the smallest copper coins in circulation, worth 1/128 of a denarius. Mark explains them for Gentile readers as equaling a <em>kodrantēs</em> — the Latin <em>quadrans</em>, 1/4 of an <em>as</em> (the Roman copper unit). This translation note shows Mark writing for a Roman audience.</p>",
"43": "<p><strong>pleion pantōn beben tōn ballontōn eis to gazophylakion</strong> — she has given more than all those throwing into the treasury — Jesus's evaluation inverts the visible calculus. <em>Pleion pantōn</em> (more than all) — not in absolute amount but in relative cost. The verb <em>beben</em> (perfect of <em>ballō</em>) — she has definitively thrown in. The calling of the disciples (<em>proskalesamenos</em>) for this teachable moment signals the importance of what they are about to hear.</p>",
"44": "<p><strong>hyperisseuontos / hysterēseōs / holon ton bion autēs</strong> — from their abundance / from her poverty/lack / her whole livelihood — <em>hyperisseuon</em> (abundance, more than enough — from <em>hyper</em> + <em>perisseuo</em>) contrasts with <em>hysterēsis</em> (lack, want, deficiency). <em>Bios</em> (life, livelihood) — she gave not merely money but the material basis of her existence. The episode functions as a narrative counterpoint to the scribes who devour widows' houses (v.40): the widow, victim of such exploitation, gives everything, while her exploiters parade their piety.</p>"
},
"13": {
"1": "<p><strong>lithoi / oikodomais</strong> — stones / buildings — The disciple's exclamation (<em>ide potapoi lithoi kai potapai oikodomiai</em>) reflects genuine awe: Herod's temple was an engineering wonder. Josephus reports that some of the retaining-wall stones measured 40–60 feet long, 10 feet high, and 14 feet deep. The temple mount platform covered 36 acres. The disciple's exclamation sets up the shocking reversal of Jesus's prophecy.</p>",
"2": "<p><strong>ou mē aphethē lithos epi lithon</strong> — not one stone shall be left upon another — the double negative <em>ou mē</em> with aorist subjunctive (<em>aphethē</em>) expresses absolute negation — an emphatic guarantee. The phrase <em>lithos epi lithon</em> (stone upon stone) is the exact reversal of what the disciple just admired. Fulfilled in 70 CE when Titus's legions destroyed the temple. Josephus describes the Roman soldiers dismantling even the foundations to remove hidden treasure and leave no basis for rebuilding.</p>",
"3": "<p><strong>kat' idian / katēnanti tou hierou</strong> — privately / opposite the temple — The private setting (<em>kat' idian</em>) with the inner circle (Peter, James, John, Andrew) mirrors other private revelatory moments in Mark (4:10–20; 7:17; 9:28). The Mount of Olives opposite the temple (across the Kidron Valley) was the site from which Ezekiel's glory-cloud departed (Ezek 11:23) and to which Zechariah expected the LORD to return for judgment (Zech 14:4).</p>",
"4": "<p><strong>pote tauta estai / to sēmeion hotan mellē tauta sytelesthai panta</strong> — when will these things be / what will be the sign when all these things are about to be fulfilled — the disciples ask two questions: (1) timing (<em>pote</em>); (2) sign (<em>sēmeion</em>). The Olivet Discourse responds to both but in ways that complicate simple identification. <em>Synteleisthai</em> (to be completely fulfilled, brought to completion) is an eschatological term with LXX resonance (Dan 12:7).</p>",
"5": "<p><strong>blepete mē tis hymas planēsē</strong> — see that no one leads you astray — <em>blepete</em> (watch out/see to it) opens the discourse and frames its dominant concern: not curiosity about end-time schedules but vigilance against deception. <em>Planēsē</em> (lead astray, deceive) from <em>planaō</em> — the same root as <em>planāsthe</em> (you are led astray) used against the Sadducees (12:24). False teaching is the primary danger.</p>",
"6": "<p><strong>egō eimi / pollous planēsousin</strong> — I am he / they will deceive many — the false figures who come claiming <em>egō eimi</em> (I am he — a Messianic self-claim) are the negative counterpart to Jesus's own truthful <em>egō eimi</em> before the High Priest (14:62). The deception is precisely the use of legitimate language for illegitimate claims. The warning is not merely about pretenders but about the dynamic of religious charisma divorced from truth.</p>",
"7": "<p><strong>dei genesthai / telos</strong> — must happen / the end — <em>dei</em> (it is necessary, divine necessity) — the same word Mark uses for Jesus's passion (8:31). The wars and rumors of wars are ordained events, not signs of imminent final consummation (<em>oupō to telos</em>, but the end is not yet). The disciples' tendency to read catastrophe as eschatological signal is deliberately corrected.</p>",
"8": "<p><strong>seismoi / limoi / archē ōdinōn</strong> — earthquakes / famines / beginning of birth pangs — <em>ōdinōn</em> (birth pangs, labor pains) is a rich OT image for eschatological tribulation (Isa 26:17; Jer 22:23; Mic 4:9–10; 1 Thess 5:3). The word suggests not the end but the onset of a process that will culminate in new life — a painful but purposive suffering. The wars, earthquakes, and famines of v.7–8 are <em>archē</em> (beginning, first stage), not the end itself.</p>",
"9": "<p><strong>paradōsousin / synedria / synagōgas / hēgemonōn / eis martyrion autois</strong> — they will hand over / councils / synagogues / governors / for a testimony to them — <em>paradidōmi</em> (hand over, betray) — the same verb used for Jesus's betrayal (9:31; 10:33; 14:10–11). The disciples' path mirrors Jesus's. <em>Eis martyrion autois</em> (for a testimony to them) — persecution becomes the occasion for witness; <em>martyrion</em> is the root of the English word martyr.</p>",
"10": "<p><strong>prōton dei kērychthēnai to euangelion eis panta ta ethnē</strong> — first the gospel must be proclaimed to all the nations — <em>prōton</em> (first) signals a sequence: before the end, universal proclamation must occur. <em>Ethnē</em> (nations, Gentiles) — the scope is global. This verse functions as both commission and assurance: world mission is not human initiative but divinely ordained necessity (<em>dei</em>). The Olivet Discourse thus embeds the Great Commission within its eschatological framework.</p>",
"11": "<p><strong>mē promerimnate / to pneuma to hagion</strong> — do not worry beforehand / the Holy Spirit — <em>promerimnate</em> (pre-worry, be anxious in advance) — only here in the NT. The prohibition targets anticipatory anxiety, not thoughtful preparation. The promised substitute for human eloquence is the Holy Spirit speaking through the disciples — an implicit pneumatology embedded in persecution-discourse.</p>",
"12": "<p><strong>paradōsei adelphos adelphon eis thanaton</strong> — brother will betray brother to death — family betrayal is one of the signs of ultimate social breakdown that Jewish apocalyptic literature associated with the end (Micah 7:6; 1 Enoch 99–100). The verb <em>paradidōmi</em> (betray/hand over) appears again, linking discipleship-persecution to Jesus's own passion.</p>",
"13": "<p><strong>misou menoi hypo pantōn / ho de hypomonōn eis telos sōthēsetai</strong> — being hated by all / the one who endures to the end will be saved — universal hatred (<em>hypo pantōn</em>, by all) is the extreme social consequence of bearing Jesus's name (<em>dia to onoma mou</em>). <em>Hypomonō</em> (to endure, remain under, persevere) is the word for active patient endurance under pressure, not passive resignation. <em>Sōthēsetai</em> (will be saved) — the final passive divine action that rewards faithful endurance.</p>",
"14": "<p><strong>bdelygma tēs erēmōseōs / ho anaginōskōn noeitō</strong> — the abomination of desolation / let the reader understand — the phrase quotes Daniel 9:27; 11:31; 12:11 (<em>bdelygma erēmōseōs</em>, the abomination that makes desolate). The original referent was Antiochus IV Epiphanes's desecration of the altar (167 BC; 1 Macc 1:54). Jesus projects the pattern forward to a future desecration. Mark's parenthetical <em>ho anaginōskōn noeitō</em> (let the reader understand) is remarkable — it breaks the narrative's fourth wall to call for interpretive discernment. <em>Hestēkota hopou ou dei</em> (standing where it ought not) uses a neuter participle for something that may be personal, which has led commentators to see a deliberately veiled reference.</p>",
"15": "<p><strong>mē katabatō / mēde eiselthō arai ti</strong> — let him not come down / nor enter to take anything — the urgency is absolute: no time for household retrieval. The flat-roofed Palestinian house had an exterior staircase to the roof. The instruction to flee directly from the roof without descending into the house conveys eschatological speed — no earthly possession justifies even momentary delay.</p>",
"16": "<p><strong>eis ta opisō epistrephasō arai to himation autou</strong> — let him not turn back to take his cloak — <em>himation</em> (cloak, outer garment) was a working man's most valuable single possession, serving as blanket and raiment. Even this must be abandoned. The instruction echoes Lot's flight from Sodom (Gen 19:17: <em>mē periblepēs eis ta opisō</em>, do not look back).</p>",
"17": "<p><strong>tais en gastri echousais / tais thēlazousais</strong> — those having in the womb / those nursing — both phrases refer to the most physically vulnerable: pregnant women whose mobility is limited and nursing mothers who cannot easily flee. The lament (<em>ouai</em>, woe) is not a curse but an expression of compassion for those for whom flight will be most dangerous.</p>",
"18": "<p><strong>proseuchesthe / hina mē genētai cheimōnos</strong> — pray / that it may not be in winter — <em>cheimōn</em> (winter) — Palestinian winter brought swollen, impassable wadis, cold, and scarce food. The command to pray for favorable flight conditions assumes that prayer can affect the circumstances of historical events — a notable eschatological-practical connection.</p>",
"19": "<p><strong>thlipsis / hoia ou gegonen toiautē ap' archēs ktiseōs</strong> — tribulation / such as has not been from the beginning of creation — the phrase echoes Daniel 12:1: <em>thlipsis hoia ou gegonen ex hou gegonen ethnos heos tēs hēmeras ekeinēs</em>. The superlative framing marks this as a unique, unrepeatable historical crisis. <em>Ap' archēs ktiseōs</em> (from the beginning of creation) extends the comparison to the whole of cosmic history.</p>",
"20": "<p><strong>ouk an esōthē pasa sarx / dia tous eklektous hous exelexato</strong> — no flesh would be saved / for the sake of the elect whom he chose — <em>pasa sarx</em> (all flesh) — the totality of human life. <em>Ekolobōsen</em> (he shortened, cut short) — divine intervention limits the tribulation's duration. The <em>eklektoi</em> (elect, chosen ones) — those chosen by God (<em>hous exelexato</em>, relative clause reinforcing divine agency) — are the reason history does not run to total destruction. Election here functions as a limit on catastrophe.</p>",
"21": "<p><strong>idou hōde ho Christos / ekeie</strong> — look, here is the Christ / there — the false Messiah-sightings (pointing: <em>hōde</em> = here, <em>ekeie</em> = there) are the deceptive signs that the discourse warned about in v.5–6. The instruction <em>mē pisteuete</em> (do not believe) is absolute — no sign-working Messiah appearing under conditions of tribulation is to be trusted.</p>",
"22": "<p><strong>pseudochristoi kai pseudoprophētai / sēmeia kai terata / apoplanān</strong> — false Christs and false prophets / signs and wonders / to lead astray — <em>pseudochristos</em> (false-Christ) is a word Mark apparently coins or inherits from early Christian apocalyptic. The coupling with <em>pseudoprophētai</em> (false prophets) mirrors the OT pairing of false prophesy with false kingship. <em>Sēmeia kai terata</em> (signs and wonders) — the credentials of prophetic authority used deceptively. <em>Ei dynaton</em> (if possible) — the conditional acknowledges divine protection of the elect even against miraculous deception.</p>",
"23": "<p><strong>hymeis de blepete / proeirēka hymin panta</strong> — but you — watch out / I have told you everything beforehand — the emphatic <em>hymeis de</em> (but you) sets the disciples apart from those who will be deceived. <em>Proeirēka</em> (I have foretold, said beforehand) — Jesus's prophylactic disclosure removes any excuse for being caught off guard. The whole discourse is simultaneously prediction and protection.</p>",
"24": "<p><strong>meta tēn thlipsin ekeinēn / ho hēlios skotisthēsetai</strong> — after that tribulation / the sun will be darkened — the temporal marker <em>meta tēn thlipsin ekeinēn</em> (after that tribulation) introduces a second phase. The celestial imagery — darkened sun, non-shining moon — cites Isaiah 13:10 (oracle against Babylon) and 34:4 (oracle against Edom). In OT prophetic usage, such cosmic convulsions regularly describe the catastrophic fall of kingdoms and the overturning of the old order, not necessarily literal astronomical events.</p>",
"25": "<p><strong>hoi asteres esontai ek tou ouranou piptontes</strong> — the stars will be falling from heaven — Isaiah 34:4 (<em>kai panta ta astra peseitai</em>). The heavenly powers (<em>hai dynameis hai en tois ouranois saleuthēsontai</em>) being shaken echoes Haggai 2:6 and Hebrews 12:26. The cumulative OT cosmic-disruption imagery functions as the backdrop for the Son of Man's arrival — the old order must be shaken for the new to arrive.</p>",
"27": "<p><strong>apostelei tous angelous / episynaxei tous eklektous ek tōn tessarōn anemōn</strong> — he will send the angels / and gather the elect from the four winds — <em>apostelei</em> (will send) — the Son of Man dispatches agents of gathering, contrasting with false prophets who scatter. <em>Episynaxei</em> (will gather together) — the prefix <em>epi-</em> intensifies the gathering as comprehensive. <em>Ek tōn tessarōn anemōn</em> (from the four winds) — the four-compass gathering appears in Daniel 7:2 and Isaiah 11:12, evoking the eschatological regathering of dispersed Israel expanded to include all the elect.</p>",
"28": "<p><strong>sykē / hē klados autēs hapalos genētai</strong> — the fig tree / when its branch becomes tender — the fig tree parable here contrasts with the cursed fig tree of 11:12–14, 20–21. There the fig tree's unfruitfulness symbolized the temple's failure; here the same species serves as a positive timing-signal. When the branch (<em>klados</em>) softens (<em>hapalos</em>, tender, supple) and leaves appear, summer is near — observable, reliable, knowable.</p>",
"29": "<p><strong>hotan idēte tauta ginomena / engys estin epi thurais</strong> — when you see these things happening / it is near at the door — the observable signs (<em>tauta</em>) indicate nearness. <em>Epi thurais</em> (at the doors) — a threshold image of imminent arrival. The disciples who asked for a sign (v.4) are given a conditional one: the signs within history point to what is near, while the ultimate day remains unknowable (v.32).</p>",
"30": "<p><strong>hē genea hautē ou mē parelthē / heos hou tauta panta genētai</strong> — this generation will certainly not pass away / until all these things have happened — one of the most debated verses in Mark. <em>Genea</em> normally means the contemporaneous generation (those alive when Jesus speaks). The double negative <em>ou mē parelthē</em> (will certainly not pass away) is emphatic. Most contemporary exegetes read this as referring to the events of 70 CE (the destruction of the temple and tribulation of vv.5–23), with vv.24–27 forming a distinct eschatological horizon. The verse as a whole stakes Jesus's prophetic credibility on near-term verifiability.</p>",
"31": "<p><strong>ho de ouranos kai hē gē pareleusontai / hoi de logoi mou ou mē parelthōsin</strong> — heaven and earth will pass away / but my words will certainly not pass away — the contrast of <em>ouranos kai gē</em> (heaven and earth — the whole created order) with <em>logoi mou</em> (my words) stakes a remarkable claim. The verbal formula <em>ou mē parelthōsin</em> (will absolutely not pass away) is the same verbal form applied to the generation in v.30. The permanence of Jesus's words exceeds the permanence of the cosmos.</p>",
"32": "<p><strong>peri de tēs hēmeras ekeinēs ē tēs hōras oudeis oiden / oude ho huios / ei mē ho patēr</strong> — but concerning that day or hour no one knows / not even the Son / but only the Father — this verse is among the most theologically significant in the Gospels. The graduated ignorance — no angel, not even <em>ho huios</em> (the Son) — limits Jesus's knowledge in his incarnate state. The early church found this verse difficult; some patristic writers handled it by distinguishing the Son's divine and human natures. The verse sits within the broader NT framework of kenosis (Phil 2:7). The unknown <em>hēmera kai hōra</em> (day and hour) is precisely what makes watchfulness necessary.</p>",
"33": "<p><strong>blepete agrypneite / ouk oidate gar pote ho kairos estin</strong> — watch out, stay awake / for you do not know when the time is — <em>agrypneite</em> (stay awake, be vigilant — literally: be sleepless) intensifies <em>blepete</em>. The reason for watchfulness is explicitly the uncertainty of timing: <em>ouk oidate pote</em> (you do not know when). The discourse does not give the disciples a timetable — it gives them an posture.</p>",
"34": "<p><strong>hōs anthrōpos apodēmos / thyrōrō / grēgorē</strong> — like a man going on a journey / to the doorkeeper / to keep watch — the parable of the absent householder: he distributes responsibility (<em>hekastō to ergon autou</em>, to each his task), with special attention to the doorkeeper. <em>Grēgorē</em> (keep watch, stay awake) — this is the imperative Jesus gives to one specific servant but which the discourse applies to all.</p>",
"35": "<p><strong>opsē ē mesonuktiō ē alektorophōnia ē prōi</strong> — evening / midnight / cockcrow / early morning — the four Roman night watches. This specific enumeration is not incidental: in the passion narrative that follows, each watch will appear. Gethsemane is late night; Peter's denial occurs at cockcrow (<em>alektorophōnia</em>, 14:68, 72); the early morning watch (<em>prōi</em>) brings Jesus before Pilate (15:1). The Olivet Discourse's watch-schedule is embedded in the passion's temporal structure.</p>",
"36": "<p><strong>exaiphnēs elthōn / katheudontas hymas heurē</strong> — suddenly coming / finds you sleeping — <em>exaiphnēs</em> (suddenly, unexpectedly — adverb of abrupt appearance) — the opposite of a scheduled, signaled arrival. <em>Katheudontas</em> (sleeping) — the disciples will fail to stay awake in Gethsemane (14:37–41) in a direct dramatic echo of this warning. The irony of their failure is prepared here.</p>",
"37": "<p><strong>ho de hymin legō pasin legō / grēgoreite</strong> — and what I say to you I say to all / Watch! — the discourse expands its audience beyond the four disciples: <em>pasin</em> (to all). <em>Grēgoreite</em> (Watch! — plural imperative) — the final word of the Olivet Discourse. This imperative will echo tragically in Gethsemane (<em>grēgoreite</em>, 14:34, 38) where the disciples sleep three times while Jesus prays. The climax of the discourse is a one-word command that the disciples will fail within hours.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'mark')
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, MARK_12_13)
    after = sum(len(v) for v in existing.values())
    save_comm('mkt-original', 'mark', existing)
    print(f'  added {after - before} entries (total: {after})')

    # Verify completeness
    import json as _json
    inter = _json.loads((ROOT / 'data' / 'interlinear' / 'mark.json').read_text())
    out = existing
    for ch in ['12', '13']:
        total = len(inter.get(ch, {}))
        present = len(out.get(ch, {}))
        status = 'complete' if present == total else f'MISSING {total - present}'
        print(f'  ch {ch}: {present}/{total} ({status})')

if __name__ == '__main__':
    main()
